import React, { useState, useEffect, useCallback } from 'react';
import { useSearchParams } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { format } from 'date-fns';
import {
  Settings as SettingsIcon,
  Clock,
  CheckSquare,
  FileText,
  HardDrive,
  Bot,
  Sliders,
  ChevronRight,
