import { Mistral } from '@mistralai/mistralai';
import type {
  AIProvider,
  AIProviderMetadata,
  AIModel,
  AIMessageOptions,
  AIResponse,
} from './types';
import { ProviderError, ProviderErrorType } from './types';

/**
 * Mistral provider metadata
 */
const METADATA: AIProviderMetadata = {
  id: 'mistral',
  name: 'Mistral AI',
  displayName: 'Mistral AI',
  description: 'European AI with privacy focus. GDPR-friendly with free tier for prototyping.',

  requiresApiKey: true,
  apiKeyUrl: 'https://console.mistral.ai/api-keys',
  apiKeyLabel: 'Mistral API Key',

  hasFreeModels: true,
  freeModelIds: [
    'mistral-small-latest',
    'mistral-medium-latest',
  ],

  freeTierLimits: {
    description: 'Free tier: Limited usage (~25 messages). Restrictive rate limits after initial use.',
  },

  supportsCORS: false,
  requiresProxy: true, // Mistral likely requires proxy, but we'll try direct
  supportsStreaming: true,

  websiteUrl: 'https://mistral.ai',
  docsUrl: 'https://docs.mistral.ai',
};

/**
 * Free models on Mistral (limited usage)
 */
const FREE_MODELS: AIModel[] = [
  {
    id: 'mistral-small-latest',
    name: 'Mistral Small Latest',
    provider: 'mistral',
    speedRating: 4,
    qualityRating: 4,
    contextWindow: 32768,
    maxOutputTokens: 8192,
    supportsStreaming: true,
    isFree: true,
    requiresApiKey: true,
    useCases: ['chat', 'code', 'analysis'],
    description: 'Mistral\'s efficient small model. Good for most tasks.',
  },
  {
    id: 'mistral-medium-latest',
    name: 'Mistral Medium Latest',
    provider: 'mistral',
    speedRating: 3,
    qualityRating: 4,
    contextWindow: 32768,
    maxOutputTokens: 8192,
    supportsStreaming: true,
    isFree: true,
    requiresApiKey: true,
    useCases: ['chat', 'code', 'reasoning', 'analysis'],
    description: 'Mistral\'s medium model. Better quality for complex tasks.',
  },
];

/**
 * Paid models on Mistral
 */
const PAID_MODELS: AIModel[] = [
  {
    id: 'mistral-large-latest',
    name: 'Mistral Large Latest',
    provider: 'mistral',
    speedRating: 3,
    qualityRating: 5,
    contextWindow: 128000,
    maxOutputTokens: 16384,
    supportsStreaming: true,
    supportsFunctionCalling: true,
    isFree: false,
    costPer1MTokens: 2.0,
    requiresApiKey: true,
    useCases: ['reasoning', 'code', 'analysis', 'creative'],
    description: 'Mistral\'s flagship model. Excellent for complex reasoning.',
  },
];

/**
 * Mistral AI Provider Implementation
 */
export class MistralProvider implements AIProvider {
  metadata = METADATA;
  models = [...FREE_MODELS, ...PAID_MODELS];

  private client: Mistral | null = null;
  private apiKey: string | null = null;

  /**
   * Check if provider is configured with API key
   */
  isConfigured(): boolean {
    return !!this.apiKey && !!this.client;
  }

  /**
   * Set API key and initialize client
   */
  setApiKey(apiKey: string): void {
    this.apiKey = apiKey;
    this.client = new Mistral({ apiKey: apiKey });
  }

  /**
   * Get current API key
   */
  getApiKey(): string | null {
    return this.apiKey;
  }

  /**
   * Clear API key and client
   */
  clearApiKey(): void {
    this.apiKey = null;
    this.client = null;
  }

  /**
   * Validate API key by making a test request
   */
  async validateApiKey(apiKey: string): Promise<boolean> {
    try {
      const testClient = new Mistral({ apiKey: apiKey });

      // Try to list models (minimal API call)
      await testClient.models.list();
      return true;
    } catch (error: any) {
      console.error('Mistral API key validation failed:', error);
      return false;
    }
  }

  /**
   * Get model by ID
   */
  getModel(modelId: string): AIModel | null {
    return this.models.find((m) => m.id === modelId) || null;
  }

  /**
   * Get default model
   */
  getDefaultModel(): AIModel {
    return FREE_MODELS[0]; // Mistral Small Latest
  }

  /**
   * Get all free models
   */
  getFreeModels(): AIModel[] {
    return FREE_MODELS;
  }

  /**
   * Send message to Mistral
   */
  async sendMessage(model: string, options: AIMessageOptions): Promise<AIResponse> {
    if (!this.client) {
      throw new ProviderError(
        ProviderErrorType.INVALID_API_KEY,
        'Mistral provider not configured. Please add your API key.',
        'mistral'
      );
    }

    try {
      const messages: Array<{ role: string; content: string }> = [];

      // Add system prompt if provided
      if (options.systemPrompt) {
        messages.push({
          role: 'system',
          content: options.systemPrompt,
        });
      }

      // Add conversation history
      if (options.conversationHistory) {
        options.conversationHistory.forEach((msg) => {
          messages.push({
            role: msg.role === 'assistant' ? 'assistant' : 'user',
            content: msg.content,
          });
        });
      }

      // Add current user prompt
      messages.push({
        role: 'user',
        content: options.prompt,
      });

      // Send request
      if (options.stream && options.onChunk) {
        // Streaming mode
        const stream = await this.client.chat.stream({
          model: model,
          messages: messages as any, // Type assertion needed for Mistral SDK compatibility
          temperature: options.temperature || 0.7,
          maxTokens: options.maxTokens || 2048,
        });

        let fullContent = '';
        for await (const chunk of stream) {
          const content = chunk.data.choices[0]?.delta?.content;
          const contentStr = typeof content === 'string' ? content : '';
          fullContent += contentStr;
          if (contentStr && options.onChunk) {
            options.onChunk(contentStr);
          }
        }

        return {
          content: fullContent,
          model: model,
          provider: 'mistral',
          finishReason: 'stop',
        };
      } else {
        // Non-streaming mode
        const response = await this.client.chat.complete({
          model: model,
          messages: messages as any, // Type assertion needed for Mistral SDK compatibility
          temperature: options.temperature || 0.7,
          maxTokens: options.maxTokens || 2048,
        });

        const content = response.choices?.[0]?.message?.content;
        const contentStr = typeof content === 'string' ? content : '';

        return {
          content: contentStr,
          model: model,
          provider: 'mistral',
          finishReason: response.choices?.[0]?.finishReason as 'stop' | 'length' | undefined,
          usage: response.usage ? {
            promptTokens: response.usage.promptTokens || 0,
            completionTokens: response.usage.completionTokens || 0,
            totalTokens: response.usage.totalTokens || 0,
          } : undefined,
        };
      }
    } catch (error: any) {
      // Map Mistral errors to ProviderError
      if (error?.statusCode === 401 || error?.message?.includes('Unauthorized')) {
        throw new ProviderError(
          ProviderErrorType.INVALID_API_KEY,
          'Invalid Mistral API key. Please check your API key and try again.',
          'mistral'
        );
      } else if (error?.statusCode === 429 || error?.message?.includes('rate limit')) {
        throw new ProviderError(
          ProviderErrorType.RATE_LIMIT,
          'Mistral rate limit exceeded. Free tier has restrictive limits after initial usage.',
          'mistral',
          true // retryable
        );
      } else if (error?.statusCode === 402 || error?.message?.includes('quota')) {
        throw new ProviderError(
          ProviderErrorType.QUOTA_EXCEEDED,
          'Mistral quota exceeded. Free tier usage exhausted (~25 messages).',
          'mistral'
        );
      } else if (error?.statusCode === 404 || error?.message?.includes('model')) {
        throw new ProviderError(
          ProviderErrorType.MODEL_NOT_FOUND,
          `Model "${model}" not found on Mistral.`,
          'mistral'
        );
      } else if (error?.message?.includes('CORS') || error?.message?.includes('fetch')) {
        throw new ProviderError(
          ProviderErrorType.NETWORK_ERROR,
          'Mistral requires backend proxy for browser use. CORS error encountered.',
          'mistral'
        );
      } else {
        throw new ProviderError(
          ProviderErrorType.UNKNOWN,
          `Mistral error: ${error?.message || 'Unknown error occurred'}`,
          'mistral'
        );
      }
    }
  }
}

